import React, { useEffect, useState } from "react";
import axios from "axios";
import { XMarkIcon } from "@heroicons/react/24/solid";

export default function UserAdm() {
  const BASE_URL = "http://localhost:8086/user";

  const [users, setUsers] = useState([]);
  const [filteredUsers, setFilteredUsers] = useState([]);
  const [search, setSearch] = useState("");
  const [loading, setLoading] = useState(true);
  const [editingUser, setEditingUser] = useState(null);

  const role = localStorage.getItem("role");

  useEffect(() => {
    fetchUsers();
  }, []);

  const fetchUsers = async () => {
    try {
      const res = await axios.get(BASE_URL);
      setUsers(res.data);
      setFilteredUsers(res.data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    const f = users.filter((u) =>
      (u.name || "").toLowerCase().includes(search.toLowerCase()) ||
      (u.email || "").toLowerCase().includes(search.toLowerCase()) ||
      (u.username || "").toLowerCase().includes(search.toLowerCase())
    );
    setFilteredUsers(f);
  }, [search, users]);

  const deleteUser = async (id) => {
    if (role !== "Admin") return alert("Access denied!");
    await axios.delete(`${BASE_URL}/${id}`);
    fetchUsers();
  };

  const updateUser = async () => {
    if (role !== "Admin") return;
    await axios.put(`${BASE_URL}/${editingUser.id}`, editingUser);
    setEditingUser(null);
    fetchUsers();
  };

  return (
    <div className="w-full">

      {/* HEADER */}
      <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-4 mb-6">
        <h1 className="text-2xl font-bold">Users</h1>

        <input
          className="px-4 py-2 rounded-lg text-black w-full md:w-80"
          placeholder="Search users..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />
      </div>

      {/* TABLE */}
      <div className="bg-white/5 backdrop-blur rounded-2xl overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full min-w-[700px] text-left">
            <thead className="bg-white/10 text-gray-300">
              <tr>
                <th className="p-4">ID</th>
                <th>Name</th>
                <th>Email</th>
                <th>Username</th>
                <th>Role</th>
                <th>Actions</th>
              </tr>
            </thead>

            <tbody>
              {filteredUsers.map((u) => (
                <tr key={u.id} className="border-t border-white/10">
                  <td className="p-4">{u.id}</td>
                  <td>{u.name}</td>
                  <td>{u.email}</td>
                  <td>{u.username}</td>

                  <td>
                    <span className="px-3 py-1 text-xs rounded-full bg-indigo-600">
                      {u.role}
                    </span>
                  </td>

                  <td className="flex gap-2 p-2">
                    <button
                      onClick={() => setEditingUser(u)}
                      className="px-3 py-1 bg-indigo-600 rounded-lg"
                    >
                      Edit
                    </button>

                    <button
                      onClick={() => deleteUser(u.id)}
                      className="px-3 py-1 bg-red-600 rounded-lg"
                    >
                      Delete
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* MODAL */}
      {editingUser && (
        <div className="fixed inset-0 bg-black/60 flex items-center justify-center p-4">
          <div className="bg-gray-900 w-full max-w-md p-6 rounded-xl relative">

            <button
              onClick={() => setEditingUser(null)}
              className="absolute top-3 right-3"
            >
              <XMarkIcon className="w-6 h-6" />
            </button>

            <h2 className="text-lg font-bold mb-4">Edit User</h2>

            <input
              className="w-full mb-3 p-2 rounded text-black"
              value={editingUser.name}
              onChange={(e) =>
                setEditingUser({ ...editingUser, name: e.target.value })
              }
            />

            <input
              className="w-full mb-3 p-2 rounded text-black"
              value={editingUser.email}
              onChange={(e) =>
                setEditingUser({ ...editingUser, email: e.target.value })
              }
            />

            <button
              onClick={updateUser}
              className="w-full bg-indigo-600 py-2 rounded-lg"
            >
              Save
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
